CustomField.formula:
IF(
CONTAINS(TEXT(Estado__c), "Creada"), IMAGE("/Obtentores/resource/Status_Icons/LicSECreada.png","Creada",24,120),
IF(
CONTAINS(TEXT(Estado__c), "A validar"), IMAGE("/Obtentores/resource/Status_Icons/LicSEAValidar.png","A validar",24,120),
IF(
CONTAINS(TEXT(Estado__c), "Validada"), IMAGE("/Obtentores/resource/Status_Icons/LicSEValidada.png","Validada",24,120),
IF(
CONTAINS(TEXT(Estado__c), "Aprobada"), IMAGE("/Obtentores/resource/Status_Icons/LicSEAprobada.png","Aprobada",24,120),
IF(
CONTAINS(TEXT(Estado__c), "Solicitada"), IMAGE("/Obtentores/resource/Status_Icons/LicSESolicitada.png","Solicitada",24,120),
IF(
CONTAINS(TEXT(Estado__c), "Firmada"), IMAGE("/Obtentores/resource/Status_Icons/LicSEFirmada.png","Firmada",24,120),
IF(
CONTAINS(TEXT(Estado__c), "En Proceso de Aprobación"), IMAGE("/Obtentores/resource/Status_Icons/LicSEEnProceso.png","En Proceso",24,120),
IF(
CONTAINS(TEXT(Estado__c), "Rechazada"), IMAGE("/Obtentores/resource/Status_Icons/LicSERechazada.png","Rechazada",24,120), ""
)
)
)
)
)
)
)
)
